// SPDX-License-Identifier: MIT
pragma solidity ^0.8.5;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";

contract PooHeadz is ERC721URIStorage, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter private _tokenIdCounter;

    uint256 public constant POOHEAD_PRICE = 0.01 ether;
    uint256 public constant MAX_POOHEAD_PURCHASE = 5;
    bool public saleIsActive;
    string public LICENSE_TEXT = "MIT License";
    bool public licenseIsLocked = false;

    event LicenseIsLocked();

    modifier whenSaleActive() {
        require(saleIsActive, "Sale is not active");
        _;
    }

    modifier whenLicenseNotLocked() {
        require(!licenseIsLocked, "License is locked");
        _;
    }

    constructor() ERC721("PooHeadz", "POOHEAD") {}

    function reservePOOHEAD(uint256[] calldata tokenIds) external onlyOwner {
        for (uint256 i = 0; i < tokenIds.length; ++i) {
            _safeMint(msg.sender, tokenIds[i]);
        }
    }

    function setBaseURI(string memory baseURI) external onlyOwner {
        _setBaseURI(baseURI);
    }

    function setLicenseText(string memory newText) external onlyOwner whenLicenseNotLocked {
        LICENSE_TEXT = newText;
    }

    function lockLicense() external onlyOwner whenLicenseNotLocked {
        licenseIsLocked = true;
        emit LicenseIsLocked();
    }

    function activateSale() external onlyOwner {
        saleIsActive = true;
    }

    function deactivateSale() external onlyOwner {
        saleIsActive = false;
    }

    function mintPOOHEAD(uint256 quantity) external payable whenSaleActive {
        require(quantity > 0 && quantity <= MAX_POOHEAD_PURCHASE, "Invalid purchase amount");
        require(msg.value >= POOHEAD_PRICE * quantity, "Insufficient funds");

        for (uint256 i = 0; i < quantity; ++i) {
            uint256 tokenId = _tokenIdCounter.current();
            _tokenIdCounter.increment();
            _safeMint(msg.sender, tokenId);
        }
    }

    function withdraw() external onlyOwner {
        address payable recipient = payable(owner());
        recipient.transfer(address(this).balance);
    }
}
