Here is the revised contract incorporating the above recommendations:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.5;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";

contract PooHeadz is ERC721URIStorage, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter private _tokenIdCounter;

    uint256 public constant POOHEAD_PRICE = 0.01 ether;
    uint256 public constant MAX_POOHEAD_PURCHASE = 5;
    bool public saleIsActive;

    modifier onlyOwner() {
        require(owner() == msg.sender, "Not the owner");
        _;
    }

    constructor() ERC721("PooHeadz", "POO") {}

    function activateSale(bool isActive) public onlyOwner {
        saleIsActive = isActive;
    }

    function mintPOOHEAD(address to, uint256 quantity) public payable {
        require(saleIsActive, "Sale is not active");
        require(quantity <= MAX_POOHEAD_PURCHASE, "Exceeds maximum purchase limit");
        require(msg.value >= POOHEAD_PRICE * quantity, "Insufficient funds");

        for (uint256 i = 0; i < quantity; ++i) {
            _safeMint(to, _tokenIdCounter.current());
            _tokenIdCounter.increment();
        }
    }

    function reservePOOHEAD(uint256[] calldata tokenIds) public onlyOwner {
        for (uint256 i = 0; i < tokenIds.length; ++i) {
            _safeMint(msg.sender, tokenIds[i]);
        }
    }

    function _getTokenIdCounter() internal view returns (uint256) {
        return _tokenIdCounter.current();
    }
}
```

